class Solution {
public:
    double findMaxAverage(vector<int>& nums, int k) {
        double ave = 0;
        double greatest = 0;
        for (int i = 0; i < k; ++i) {
            ave += nums[i];
        }
        greatest = ave;

        for (int i = k; i < nums.size(); ++i) {
            ave += nums[i] - nums[i - k]; 
            greatest = max(greatest, ave); 
        }

    return greatest / k;
    }
};
